class Solution(object):
    def countMatchingSubarrays(self, nums, pattern):
        n, m = len(nums), len(pattern)
        count = 0
        for i in range(n - m):
            match = True
            for k in range(m):
                a, b = nums[i + k], nums[i + k + 1]
                if pattern[k] == 1 and not (b > a):
                    match = False
                    break
                elif pattern[k] == 0 and not (b == a):
                    match = False
                    break
                elif pattern[k] == -1 and not (b < a):
                    match = False
                    break
            if match:
                count += 1
        return count
